document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("bookingSummary"),t=JSON.parse(localStorage.getItem("ss-package")),n=JSON.parse(localStorage.getItem("ss-addons"));if(e&&t){let a=`Package: ${t.name} — $${t.price}`;n&&(a+=` | Add‑Ons: $${n.hourPrice+n.travelFee+n.toastPrice}`),e.textContent=a}});
